7140	/* Execute one parsed DSML tool call and return the text that will be appended as
7141	 * the tool-role result.  UI visualization already happened while streaming; this
7142	 * function is only about side effects and the model-visible observation. */
7143	static char *agent_execute_tool_call(agent_worker *w, const agent_tool_call *call) {
7144	    agent_buf result = {0};
7145	    if (!call->name) return xstrdup("Tool error: missing tool name\n");
7146	
7147	    if (!strcmp(call->name, "read")) return agent_tool_read(w, call);
7148	    if (!strcmp(call->name, "more")) return agent_tool_more(w, call);
7149	    if (!strcmp(call->name, "write")) return agent_tool_write(w, call);
7150	    if (!strcmp(call->name, "list")) return agent_tool_list(call);
7151	    if (!strcmp(call->name, "edit")) return agent_tool_edit(w, call);
7152	    if (!strcmp(call->name, "search")) return agent_tool_search(w, call);
7153	    if (!strcmp(call->name, "google_search")) return agent_tool_google_search(w, call);
7154	    if (!strcmp(call->name, "visit_page")) return agent_tool_visit_page(w, call);
7155	
7156	    if (!strcmp(call->name, "bash")) {
7157	        const char *cmd = agent_tool_arg_value(call, "command");
7158	        if (!cmd || !cmd[0]) return xstrdup("Tool error: bash requires command\n");
7159	        int timeout = agent_parse_timeout(agent_tool_arg_value(call, "timeout_sec"));
7160	        int refresh = agent_parse_int_default(agent_tool_arg_value(call, "refresh_sec"),
7161	                                              60, 1, 3600);
7162	        char err[160] = {0};
7163	        agent_bash_job *job = agent_bash_start(w, cmd, timeout, err, sizeof(err));
7164	        if (!job) {
7165	            agent_buf_puts(&result, "Tool error: bash failed to start: ");
7166	            agent_buf_puts(&result, err[0] ? err : "unknown error");
7167	            agent_buf_puts(&result, "\n");
7168	            return agent_buf_take(&result);
7169	        }
7170	        return agent_bash_job_tool_result(w, job, true, refresh, false, true);
7171	    }
7172	
7173	    if (!strcmp(call->name, "bash_status") ||
7174	        !strcmp(call->name, "bash_stop"))
7175	    {
7176	        int job_id = agent_tool_job_id(call);
7177	        pid_t pid = agent_tool_pid(call);
7178	        agent_bash_job *job = agent_bash_find_job(w, job_id, pid);
7179	        if (!job) {
7180	            char msg[128];
7181	            snprintf(msg, sizeof(msg), "Tool error: bash job not found: job=%d pid=%ld\n",
7182	                     job_id, (long)pid);
7183	            return xstrdup(msg);
7184	        }
7185	        int refresh = agent_parse_int_default(agent_tool_arg_value(call, "refresh_sec"),
7186	                                              60, 1, 3600);
7187	        bool stop = !strcmp(call->name, "bash_stop");
7188	        bool wait = stop;
7189	        return agent_bash_job_tool_result(w, job, wait, refresh, stop, true);
7190	    }
7191	
7192	    {
